const items = $input.all();
const results = [];

function getHeaderValue(headers, name) {
  if (!Array.isArray(headers)) return '';
  const match = headers.find((h) => (h.name || '').toLowerCase() === name.toLowerCase());
  return match ? (match.value || '') : '';
}

// Some n8n Gmail node versions parse From/Subject/Date into objects
// (e.g. { text, html, value: [{ name, address }] }) instead of plain
// strings — normalize whatever shape shows up into a plain string.
function toText(value) {
  if (typeof value === 'string') return value;
  if (value && typeof value === 'object') {
    if (typeof value.text === 'string') return value.text;
    if (Array.isArray(value.value) && value.value[0]) {
      const v = value.value[0];
      return ((v.name ? v.name + ' ' : '') + (v.address ? '<' + v.address + '>' : '')).trim();
    }
  }
  return '';
}

function parseSender(rawValue) {
  const raw = (typeof rawValue === 'string' ? rawValue : String(rawValue || '')).trim();
  const m = raw.match(/^(.*?)<(.+?)>$/);
  if (m) {
    return { name: m[1].trim().replace(/^"|"$/g, ''), email: m[2].trim() };
  }
  return { name: '', email: raw };
}

function isPdfAttachment(bin) {
  const mime = (bin.mimeType || '').toLowerCase();
  const name = (bin.fileName || '').toLowerCase();
  return mime === 'application/pdf' || name.endsWith('.pdf');
}

for (const item of items) {
  const data = item.json || {};
  const headers = data.payload && data.payload.headers;

  const fromRaw = toText(data.From) || toText(data.from) || getHeaderValue(headers, 'From') || '';
  const subject = toText(data.Subject) || toText(data.subject) || getHeaderValue(headers, 'Subject') || '(no subject)';
  const dateRaw = toText(data.Date) || toText(data.date) || getHeaderValue(headers, 'Date') || '';
  const { name: senderName, email: senderEmail } = parseSender(fromRaw);

  let receivedAt;
  if (dateRaw) {
    const parsed = new Date(dateRaw);
    receivedAt = isNaN(parsed.getTime()) ? new Date().toISOString() : parsed.toISOString();
  } else if (data.internalDate) {
    receivedAt = new Date(Number(data.internalDate)).toISOString();
  } else {
    receivedAt = new Date().toISOString();
  }

  // Don't assume a specific binary key naming convention (e.g. "attachment_0")
  // — scan every binary key on the item and identify PDFs by MIME type or
  // filename instead. Gmail Trigger items only carry actual email attachments
  // in `binary`, so there's nothing else these keys could be.
  const binary = item.binary || {};

  for (const key of Object.keys(binary)) {
    const bin = binary[key];
    if (!isPdfAttachment(bin)) continue;

    results.push({
      json: {
        fileName: bin.fileName || 'resume.pdf',
        senderEmail,
        senderName,
        subject,
        receivedAt
      },
      binary: { data: bin }
    });
  }
}

return results;

const source = $('Filter PDF Attachments').item.json;
const uploaded = $json;

return {
  json: {
    id: uploaded.id,
    fileName: source.fileName,
    senderEmail: source.senderEmail,
    senderName: source.senderName,
    subject: source.subject,
    receivedAt: source.receivedAt,
    driveFileId: uploaded.id
  }
};
